sql:
SELECT tool_id, COUNT(*) AS number_of_versions
FROM tool_versions
GROUP BY tool_id;

SELECT tool_id, COUNT(comment_id) AS total_comments
FROM tool_comments
GROUP BY tool_id;

SELECT SIN(CAST(identity_id AS REAL)) AS sine_of_identity_id
FROM identities
WHERE identity_id IS NOT NULL;

SELECT user_id, user_name, email, role
FROM users
WHERE email NOT IN (
    SELECT email
    FROM identities
);

SELECT COUNT(version_id) 
FROM tool_versions 
WHERE tool_id = 'specific_tool_id';

SELECT COUNT(DISTINCT access_logs.user_id) AS unique_users
FROM access_logs
JOIN external_references ON access_logs.tool_id = external_references.external_id;

SELECT er.source_name, er.url, er.description
FROM external_references er
WHERE er.external_id = 'tool_id_here';

SELECT COUNT(user_id) AS total_ratings 
FROM tool_ratings 
WHERE tool_id = 'tool_id';

SELECT tool_id, AVG(rating_score) AS average_rating
FROM tool_ratings
GROUP BY tool_id;
